import os
import json
import argparse
import heapq
import numpy as np
from cogniplan_env import ExplorationEnv


def build_graph(nodes):
    coord_to_idx = {}
    coords = []
    for i, n in enumerate(nodes):
        c = tuple(np.round(np.array(n['coords']), 2))
        coord_to_idx[c] = i
        coords.append(np.array(n['coords'], dtype=float))
    adj = [[] for _ in range(len(nodes))]
    for i, n in enumerate(nodes):
        for nb in n.get('neighbors', []):
            ct = tuple(np.round(np.array(nb), 2))
            j = coord_to_idx.get(ct)
            if j is not None and j != i:
                d = float(np.linalg.norm(coords[i] - coords[j]))
                adj[i].append((j, d))
    return coord_to_idx, coords, adj


def dijkstra(adj, start):
    n = len(adj)
    dist = [float('inf')] * n
    prev = [-1] * n
    dist[start] = 0.0
    pq = [(0.0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u]:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(pq, (nd, v))
    return dist, prev


def path_first_step(prev, start, target):
    if target == start:
        return target
    if prev[target] == -1:
        return target
    cur = target
    while prev[cur] != start and prev[cur] != -1:
        cur = prev[cur]
    return cur


def plan_episode(map_path, max_steps=128):
    env = ExplorationEnv(map_path=map_path)
    obs = env.reset()

    last_target_coord = None

    for step in range(max_steps):
        try:
            neighbors = obs['neighbors']
            nodes = obs['nodes']
            explored_rate = obs.get('explored_rate', 0.0)
        except Exception:
            break
        if not neighbors or not nodes:
            break
        robot = np.array(obs['robot_pos'], dtype=float)

        coord_to_idx, coords, adj = build_graph(nodes)
        if len(coords) == 0:
            break
        dists_to_robot = [np.linalg.norm(c - robot) for c in coords]
        start_idx = int(np.argmin(dists_to_robot))
        dist, prev = dijkstra(adj, start_idx)

        # Two-phase scoring:
        # - Early/mid (<0.85): utility / (d+1) — global exploration
        # - Late (>=0.85): 1 / (d+1) for utility>0 — nearest frontier sweep
        late_phase = explored_rate >= 0.85

        scored = []
        for i, nd in enumerate(nodes):
            if i == start_idx:
                continue
            u = nd.get('utility', 0)
            if u <= 0:
                continue
            d = dist[i]
            if d == float('inf'):
                continue
            if late_phase:
                score = 1.0 / (d + 1.0)
            else:
                score = u / (d + 1.0)
            scored.append((score, i, u, d))
        scored.sort(reverse=True)

        chosen = None
        target_idx = -1
        if scored:
            # Target persistence: if last target still in scored top-3 with similar score, keep it
            target_idx = scored[0][1]
            if last_target_coord is not None:
                # Find if last target still has utility
                for sc, idx, u, d in scored[:5]:
                    if np.linalg.norm(coords[idx] - last_target_coord) < 0.5:
                        # Stick with previous target if score is close to best
                        if sc >= scored[0][0] * 0.75:
                            target_idx = idx
                        break
            next_idx = path_first_step(prev, start_idx, target_idx)
            next_coord = coords[next_idx]
            chosen = min(neighbors, key=lambda c: np.linalg.norm(np.array(c) - next_coord))
            last_target_coord = coords[target_idx].copy()
        else:
            last_target_coord = None
            # Fallback: go to nearest unvisited node via shortest path
            best_d = float('inf')
            best_idx = -1
            for i, nd in enumerate(nodes):
                if i == start_idx:
                    continue
                if nd.get('visited', False):
                    continue
                d = dist[i]
                if d < best_d and d > 0:
                    best_d = d
                    best_idx = i
            if best_idx >= 0:
                next_idx = path_first_step(prev, start_idx, best_idx)
                next_coord = coords[next_idx]
                chosen = min(neighbors, key=lambda c: np.linalg.norm(np.array(c) - next_coord))
            else:
                chosen = neighbors[0]

        try:
            obs, info = env.step(chosen)
        except Exception as e:
            break
        if info.get('done', False):
            break

    metrics = env.get_metrics()
    return metrics


def main():
    ap = argparse.ArgumentParser()
    ap.add_argument('--data_path', required=True)
    ap.add_argument('--checkpoint', required=False, default=None)
    ap.add_argument('--output', required=True)
    args = ap.parse_args()

    cfg_path = os.path.join(args.data_path, 'eval_config.json')
    episodes = []
    if os.path.exists(cfg_path):
        try:
            with open(cfg_path) as f:
                cfg = json.load(f)
            if isinstance(cfg, dict):
                episodes = cfg.get('episodes') or cfg.get('maps') or cfg.get('eval_maps') or []
            elif isinstance(cfg, list):
                episodes = cfg
        except Exception:
            episodes = []

    maps_dir = os.path.join(args.data_path, 'maps_eval')
    if not episodes and os.path.isdir(maps_dir):
        for sub in sorted(os.listdir(maps_dir)):
            sd = os.path.join(maps_dir, sub)
            if os.path.isdir(sd):
                for fn in sorted(os.listdir(sd)):
                    if fn.lower().endswith(('.png', '.jpg', '.jpeg')):
                        episodes.append({'map_path': f'{sub}/{fn}', 'env_type': sub})

    per_episode = []
    per_type = {}
    explored_rates = []
    success_dists = []
    n_success = 0

    for ep in episodes:
        mp_rel = ep.get('map_path') if isinstance(ep, dict) else ep
        env_type = ep.get('env_type', 'unknown') if isinstance(ep, dict) else 'unknown'
        # Find absolute path
        candidates = [
            os.path.join(args.data_path, 'maps_eval', mp_rel),
            os.path.join(args.data_path, mp_rel),
            mp_rel,
        ]
        full_path = None
        for c in candidates:
            if os.path.exists(c):
                full_path = c
                break
        if full_path is None:
            per_episode.append({'map_path': mp_rel, 'env_type': env_type, 'success': 0,
                                'travel_distance': 0.0, 'explored_rate': 0.0})
            continue

        try:
            metrics = plan_episode(full_path)
        except Exception as e:
            per_episode.append({'map_path': mp_rel, 'env_type': env_type, 'success': 0,
                                'travel_distance': 0.0, 'explored_rate': 0.0})
            continue

        success = 1 if metrics.get('explored_rate', 0.0) > 0.9999 else 0
        td = float(metrics.get('travel_distance', 0.0))
        er = float(metrics.get('explored_rate', 0.0))

        per_episode.append({'map_path': mp_rel, 'env_type': env_type, 'success': success,
                            'travel_distance': td, 'explored_rate': er})
        explored_rates.append(er)
        if success:
            n_success += 1
            success_dists.append(td)

        if env_type not in per_type:
            per_type[env_type] = {'er': [], 'td_succ': [], 'n': 0, 'n_succ': 0}
        per_type[env_type]['er'].append(er)
        per_type[env_type]['n'] += 1
        if success:
            per_type[env_type]['n_succ'] += 1
            per_type[env_type]['td_succ'].append(td)

    n = len(per_episode)
    out = {
        'explored_rate': float(np.mean(explored_rates)) if explored_rates else 0.0,
        'travel_distance': float(np.mean(success_dists)) if success_dists else 0.0,
        'success_rate': n_success / n if n else 0.0,
        'per_episode': per_episode,
        'per_type': {},
        'total_episodes': n,
    }
    for k, v in per_type.items():
        out['per_type'][k] = {
            'explored_rate': float(np.mean(v['er'])) if v['er'] else 0.0,
            'travel_distance': float(np.mean(v['td_succ'])) if v['td_succ'] else 0.0,
            'success_rate': v['n_succ'] / v['n'] if v['n'] else 0.0,
        }

    with open(args.output, 'w') as f:
        json.dump(out, f)


if __name__ == '__main__':
    main()
